import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{o,c as i,f as e}from"./app-e7c604ce.js";const t={},d=e('<h3 id="场景" tabindex="-1"><a class="header-anchor" href="#场景" aria-hidden="true">#</a> 场景</h3><ol><li>做实验的最终目的是得出一个包括各个过程的报告，</li><li>走完前面的任务创建、样品采样、数据录入、选择实验工具、结果计算各个流程后，最后是生成报告的流程。</li><li>拿到了前面各个流程的数据，报告就可以一键生成且在页面上预览。</li></ol><h3 id="难点" tabindex="-1"><a class="header-anchor" href="#难点" aria-hidden="true">#</a> 难点</h3><ol><li>报告内容包括实验步骤说明、表格、复杂表格、图片列表、结论等等，印象比较深的是导出一份64页的报告，都是表格数据与结论。</li><li>不同子类型的检测项目报告内容差异很大，所以需要定制多个报告模板，生成报告时选择对应的模板生成数据。</li></ol><h3 id="解决方案" tabindex="-1"><a class="header-anchor" href="#解决方案" aria-hidden="true">#</a> 解决方案</h3><ol><li>方案一：市面上生成docx文件的库有很多个：比如说<code>docx</code>库支持复杂格式（表格、页眉页脚、样式等）但是不支持使用现成的word模版； <ul><li>可以直接使用docx 库手动写上各种样式、数据，但是内容过多一般是几十页，所以使用模板与传入的数据结构效率更高、时间更快。</li></ul></li><li>方案二：生成报告最终是选择了<code>docxtemplater</code>这个库，它是需要准备Word模板文件，填入数据一般用占位符{}。可以保留模板格式，支持复杂数据结构</li></ol><h3 id="实现" tabindex="-1"><a class="header-anchor" href="#实现" aria-hidden="true">#</a> 实现</h3><ol><li>原理：利用模板中的占位符与JSON数据对象中的属性进行匹配，替换模板中的相应内容，从而生成特定的文档。 <ul><li>这一过程的核心是模板引擎的解析和替换机制。</li></ul></li><li>根据不同类型的报告定制多个报告模板，用户选择模板点击确定后开始生成。 <ul><li>报告模板是根据用户提供的表格与格式，文字改为变量名，增加批注设置变量的类型；</li><li>模板写上图片变量名字name并批注上<code>DataType=1|W=500|H=198</code>来设置值为图片类型、以及图片的宽高</li></ul></li><li>根据用户选择模板请求文档服务取出word模板的模板结构参数。 <ul><li>比如：<code>[{&quot;DataType&quot;: &quot;0&quot;,&quot;Bind&quot;: &quot;ReportNumber&quot;},{&quot;DataType&quot;: &quot;8&quot;, &quot;Bind&quot;: &quot;MonitorContent_Gas_Rows&quot;,}]</code></li></ul></li><li>请求实验各个流程中的报告相关数据，主要是前面做实验的一些数据，组装传入模板的数据对象 <ul><li>比如：<code>{&quot;ReportNumber&quot;: &quot;ST20242399&quot;, &quot;MonitorContent_Gas_List&quot;: [{&quot;Place&quot;: &quot;DA001处理前&quot;, &quot;Items&quot;: &quot;硫酸雾&quot;,&quot;PickTimeStr&quot;: &quot;2024.09.10&quot;},]}</code></li></ul></li><li>精准匹配报告模板的数据结构，仅保留模板上存在字段的非空内容 <ul><li>①使用函数<code>matchDataByStruct</code>，传入数据对象以及<code>struct</code>模板结构，一一比较他们</li><li>②根据模板结构数组的<code>datatype</code>去检测数据对象中数据类型是否符合，不符合的字段会被删除</li></ul></li><li>调用文件生成服务，生成文档并上传，文档生成一份PDF文件并保存；</li><li>前端展示报告，生成后返回pdf的文件路径，报告pdf预览使用<code>kkFileView</code>预览接口实现在线文档预览。先部署，启动运行。 <ul><li>需要处理预览文件的地址：①补齐文件路径，<code>Base64.encode(url)</code>把url变成Base64编码，再使用<code>encodeURIComponent()</code>进行URI编码</li><li>②预览接口拼接编码后的文件路径，显示在<code>iframe</code>上，文件就可以预览了。</li></ul></li></ol><h3 id="坑点" tabindex="-1"><a class="header-anchor" href="#坑点" aria-hidden="true">#</a> 坑点</h3><ol><li>导出一开始容易出现导出失败 <ul><li>解决：做好数据校验。数据格式匹配有问题，或者数据数据为空白，总是容易出现问题。所以生成之前需要<code>matchDataByStruct</code>严格校验一下</li></ul></li><li>导出时间过长 <ul><li>解决：数据量大时候不写双for循环代码，改为对象获取的时间复杂度更低。</li><li>设计好缓存结构，比如任务的每个流程实验数据都做好缓存，节省查询时间。</li></ul></li><li>生成word转pdf复杂公式乱码问题 <ul><li>解决：字体兼容问题，没有相关字体，只能模板贴上小图片。</li></ul></li><li>有些客户需要生成的文档加上水印 <ul><li>解决：模板加上水印、页眉加上图片。生成报告的每一页都会有这些内容。</li></ul></li><li>目录的生成有问题 <ul><li>有些实验报告的检测项目有多个，大标题是动态生成的。由于渲染问题，先渲染基础目录，再根据数据生成表格，目录会显示不完整</li><li>所以在调用文件生成服务时候，内部需要先刷新获取目录的最新内容，再生成文档。</li></ul></li></ol>',10),u=[d];function a(c,r){return o(),i("div",null,u)}const q=l(t,[["render",a],["__file","一键生成实验报告word文档.html.vue"]]);export{q as default};
